\end{equation}

perturbations.original:
\begin{equation}
    \label{eq: obj}
    f(v) 
    \coloneqq \frac{\scp{v}{A^{\tT}A v}}{\scp{v}{B^{\tT}B v}}
    = \frac{\norm{A v}^2}{\norm{B v}^2}
\end{equation}

