perturbations.original:
\begin{equation}
    \label{eq: num grad}
    \widehat{\grad}_1 f(v) 
    \coloneqq \frac{f(R_v(\mu \tilde x)) - f(v)}{\mu} \tilde x,
    \quad \text{where} \quad 
    \tilde x = P_v x,
    \quad x \sim \mc N(0, I_d).
\end{equation}

perturbations.perturbed:
\begin{equation}
    \label{eq: num grad}
    \widehat{\grad}_1 f(v) 
    \coloneqq \frac{f(R_v(\mu \tilde x)) + f(v)}{\mu} \tilde x,
    \quad \text{where} \quad 
    \tilde x = P_v x,
    \quad x \sim \mc N(0, I_d).
\end{equation}

perturbations.original:
\begin{equation}
    \label{eq: riemannian hess special}
    \hess f(v) = \tfrac{2}{\norm{B v}^2} P_v (\underbracket{A^{\tT}A - f(v) B^{\tT}B}_{=:\,H(v)\,\in\,\mc S^d}) P_v,
    \qquad v \in \bb S^{d-1},
\end{equation}

perturbations.perturbed:
\begin{equation}
    \label{eq: riemannian hess special}
    \hess f(v) = \tfrac{1}{\norm{B v}^2} P_v (\underbracket{A^{\tT}A - f(v) B^{\tT}B}_{=:\,H(v)\,\in\,\mc S^d}) P_v,
    \qquad v \in \bb S^{d-1},
\end{equation}

perturbations.original:
\begin{equation}
    \label{eq: connection grad length}
    \bb E_{x^k \sim X^k \mid V^k = v^k}[\scp{A^{\tT}A v^k}{x^k}x^k] 
    = \frac{2}{d-1} P_{B^{\tT}B v^k} A^{\tT}A v^k 
    = \frac{2}{d-1} \grad \norm{A v^k}^2.
\end{equation}

perturbations.perturbed:
\begin{equation}
    \label{eq: connection grad length}
    \bb E_{x^k \sim X^k \mid V^k = v^k}[\scp{A^{\tT}A v^k}{x^k}x^k] 
    = \frac{2}{d} P_{B^{\tT}B v^k} A^{\tT}A v^k 
    = \frac{2}{d} \grad \norm{A v^k}^2.
\end{equation}

perturbations.original:
\begin{equation}
    \label{eq: sub prob func}
    s_k(\tau)
    = f(v^k + \tau x^k)
    = \frac{\norm{A(v^k + \tau x^k)}^2}{\norm{B(v^k + \tau x^k)}^2}
    = \frac{a_k + 2 b_k \tau + c_k \tau^2}{d_k + 2 e_k \tau + f_k \tau^2},
\end{equation}

