perturbations.original:
\begin{equation}
    \label{eq: sum d e f}
    \norm{v^k + \tau x^k}^2_{B^{\tT}B} 
    \geq \lambda_d(B^{\tT}B) \norm{v^k + \tau x^k}^2
    \geq 2 \lambda_d(B^{\tT}B) (1 - \langle x^k, v^k\rangle^2)
    > 0.
\end{equation}

